@Component
export struct SvgIcon {
  @Prop iconSize: number = 24;
  @Prop color: string = '#3E2723';
  @Prop strokeWidth: number = 2;
  @Prop variant: string = 'search';

  build() {
    Image($rawfile(this.fileNameForVariant()))
      .width(this.iconSize)
      .height(this.iconSize)
      .objectFit(ImageFit.Contain)
      .fillColor(this.color)
      .draggable(false)
  }

  private fileNameForVariant(): string {
    const v: string = this.variant;
    if (v === 'home') {
      return this.activeSuffix('首页标签');
    } else if (v === 'wheel') {
      return this.activeSuffix('转盘标签');
    } else if (v === 'ingredients') {
      return this.activeSuffix('食材标签');
    } else if (v === 'discover') {
      return this.activeSuffix('发现标签');
    } else if (v === 'records') {
      return this.activeSuffix('记录标签');
    } else if (v === 'back') {
      return 'icon_返回上一页.svg';
    } else if (v === 'add') {
      return 'icon_添加今日饮食打卡.svg';
    } else if (v === 'remove') {
      return 'icon_删除该转盘项.svg';
    } else if (v === 'search') {
      return 'icon_搜索饮品.svg';
    } else if (v === 'chefHat') {
      return 'icon_今日推荐菜品插图.svg';
    } else if (v === 'wheelPointer') {
      return 'icon_转盘指针.svg';
    } else if (v === 'wheelCenter') {
      return 'icon_转盘中心装饰.svg';
    } else if (v === 'spin') {
      return 'icon_开始转动转盘.svg';
    } else if (v === 'fridge') {
      return 'icon_打开冰箱食材管理.svg';
    } else if (v === 'discoverIcon') {
      return 'icon_打开发现页筛选菜品.svg';
    } else if (v === 'recordsIcon') {
      return 'icon_打开饮食打卡记录.svg';
    } else if (v === 'wheelIcon') {
      return 'icon_打开随机转盘抽菜.svg';
    } else if (v === 'dish1') {
      return 'icon_菜品插图-1.svg';
    } else if (v === 'dish2') {
      return 'icon_菜品插图-2.svg';
    } else if (v === 'dish3') {
      return 'icon_菜品插图-3.svg';
    } else if (v === 'dish4') {
      return 'icon_菜品插图-4.svg';
    } else if (v === 'recommend1') {
      return 'icon_推荐菜品插图-1.svg';
    } else if (v === 'recommend2') {
      return 'icon_推荐菜品插图-2.svg';
    } else if (v === 'checkin1') {
      return 'icon_打卡菜品图标-1.svg';
    } else if (v === 'checkin2') {
      return 'icon_打卡菜品图标-2.svg';
    } else if (v === 'checked') {
      return 'icon_已打卡.svg';
    } else if (v === 'edit') {
      return 'icon_编辑这条打卡.svg';
    } else if (v === 'trash') {
      return 'icon_删除这条打卡.svg';
    } else if (v === 'share') {
      return 'icon_生成分享卡片.svg';
    } else if (v === 'save') {
      return 'icon_保存卡片到相册.svg';
    } else if (v === 'systemShare') {
      return 'icon_调用系统分享.svg';
    } else if (v === 'arrowRight') {
      return 'icon_选择该推荐菜品.svg';
    } else if (v === 'award') {
      return 'icon_连续打卡奖章.svg';
    } else if (v === 'shareDish') {
      return 'icon_分享卡片菜品插图.svg';
    } else if (v === 'wheelResult') {
      return 'icon_抽中菜品插图.svg';
    } else if (v === 'addIngredient') {
      return 'icon_添加食材到冰箱.svg';
    } else if (v === 'addDish') {
      return 'icon_添加自定义菜品.svg';
    } else if (v === 'addWheelItem') {
      return 'icon_添加自定义转盘项.svg';
    } else if (v === 'jumpWheel') {
      return 'icon_跳转随机转盘页面.svg';
    }
    return 'icon_搜索饮品.svg';
  }

  private activeSuffix(base: string): string {
    // Active/inactive icon pairs are named with -1 (inactive) and -2 (active)
    const suffix: string = this.color === '#E85D4E' ? '2' : '1';
    return `icon_${base}-${suffix}.svg`;
  }
}
