import { Theme } from '../common/Theme';
import { TabId } from '../common/TabTypes';
import { BottomTabBar } from '../components/BottomTabBar';

import { HomePage } from '../pages/HomePage';
import { WheelPage } from '../pages/WheelPage';
import { IngredientsPage } from '../pages/IngredientsPage';
import { DiscoverPage } from '../pages/DiscoverPage';
import { RecordsPage } from '../pages/RecordsPage';
import { ShareCardPage } from '../pages/ShareCardPage';

type AppSurface =
  | 'home'
  | 'wheel'
  | 'ingredients'
  | 'discover'
  | 'records'
  | 'share-card';

@Entry
@Component
struct Index {
  @State surface: AppSurface = 'home';
  @State activeTab: TabId = 'tab-home';
  @State lastTabBeforePush: TabId = 'tab-home';

  build() {
    Stack() {
      Stack({ alignContent: Alignment.Bottom }) {
        Column() {
          this.CurrentSurface()
        }
        .width('100%')
        .height('100%')
        .padding({
          bottom: this.isTabSurface(this.surface) ? Theme.bottomTabHeight + 8 : 0
        })

        if (this.isTabSurface(this.surface)) {
          BottomTabBar({
            activeTab: this.activeTab,
            onTap: (tab: TabId): void => this.goToTab(tab),
          })
        }
      }
      .width('100%')
      .height('100%')
    }
    .width('100%')
    .height('100%')
    .backgroundColor(Theme.pageBg)
  }

  @Builder
  CurrentSurface() {
    if (this.surface === 'home') {
      HomePage({
        goToTab: (tab: TabId): void => this.goToTab(tab),
        onCheckIn: (): void => this.openRecordsCheckIn(),
      })
    } else if (this.surface === 'wheel') {
      WheelPage({
        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
        onShareCard: (): void => this.pushSurface('share-card'),
        onAddCheckin: (dish: string): void => {
          // TODO: add check-in with dish
          this.goToTab('tab-records');
        },
      })
    } else if (this.surface === 'ingredients') {
      IngredientsPage({
        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
        onCook: (dish: string): void => {
          // TODO: mark as cooked
        },
      })
    } else if (this.surface === 'discover') {
      DiscoverPage({
        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
        onAddDish: (): void => {},
      })
    } else if (this.surface === 'records') {
      RecordsPage({
        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
        onShareCard: (): void => this.pushSurface('share-card'),
        onTodayCheckIn: (): void => {},
        onEdit: (id: string): void => {},
        onDelete: (id: string): void => this.deleteCheckIn(id),
      })
    } else if (this.surface === 'share-card') {
      ShareCardPage({
        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
      })
    }
  }

  private isTabSurface(s: AppSurface): boolean {
    return s === 'home' || s === 'wheel' || s === 'ingredients' || s === 'discover' || s === 'records';
  }

  private goToTab(tab: TabId): void {
    this.activeTab = tab;
    if (tab === 'tab-home') {
      this.surface = 'home';
    } else if (tab === 'tab-wheel') {
      this.surface = 'wheel';
    } else if (tab === 'tab-ingredients') {
      this.surface = 'ingredients';
    } else if (tab === 'tab-discover') {
      this.surface = 'discover';
    } else if (tab === 'tab-records') {
      this.surface = 'records';
    }
  }

  private returnToTab(tab: TabId): void {
    this.goToTab(tab);
  }

  private pushSurface(surface: AppSurface): void {
    this.lastTabBeforePush = this.activeTab;
    this.surface = surface;
  }

  private openRecordsCheckIn(): void {
    this.goToTab('tab-records');
  }

  private deleteCheckIn(id: string): void {
    // TODO: remove check-in from store
  }
}
