197	  private activeSuffix(base: string): string {
198	    // Active/inactive icon pairs are named with -1 (inactive) and -2 (active)
199	    const suffix: string = this.color === '#E85D4E' ? '2' : '1';
200	    return `icon_${base}-${suffix}.svg`;
201	  }
