215	interface TabDescriptor {
216	  id: TabId;
217	  label: string;
218	  icon: string;
219	}
220	
221	const TABS: TabDescriptor[] = [
222	  { id: 'tab-home', label: '首页', icon: 'home' },
223	  { id: 'tab-wheel', label: '转盘', icon: 'wheel' },
224	  { id: 'tab-ingredients', label: '食材', icon: 'ingredients' },
225	  { id: 'tab-discover', label: '发现', icon: 'discover' },
226	  { id: 'tab-records', label: '记录', icon: 'records' },
227	];
228	
229	@Component
230	export struct BottomTabBar {
231	  @Prop activeTab: TabId;
232	  onTap: (tab: TabId) => void = () => {};
233	
234	  build() {
235	    Row() {
236	      ForEach(TABS, (tab: TabDescriptor) => {
237	        Column() {
238	          SvgIcon({
239	            variant: tab.icon,
240	            iconSize: 24,
241	            color: this.activeTab === tab.id ? Theme.tomato : Theme.brownLight,
242	            strokeWidth: 2
243	          })
244	          Text(tab.label)
245	            .fontSize(11)
246	            .fontWeight(FontWeight.Medium)
247	            .fontColor(this.activeTab === tab.id ? Theme.tomato : Theme.brownLight)
248	            .margin({ top: 4 })
249	        }
250	        .id(tab.id)
251	        .padding({ left: 8, right: 8, top: 6, bottom: 6 })
252	        .onClick(() => this.onTap(tab.id))
253	        .layoutWeight(1)
254	        .alignItems(HorizontalAlign.Center)
255	      }, (tab: TabDescriptor) => tab.id)
256	    }
257	    .id('bottom-tab-bar')
258	    .width('100%')
259	    .height(Theme.bottomTabHeight)
260	    .padding({ bottom: 8 })
261	    .backgroundColor('rgba(255,251,245,0.94)')
262	    .border({ width: { top: 1 }, color: { top: Theme.borderSoft } })
263	    .justifyContent(FlexAlign.SpaceAround)
264	    .alignItems(VerticalAlign.Center)
265	  }
266	}
