286	
287	@Entry
288	@Component
289	struct Index {
290	  @State surface: AppSurface = 'home';
291	  @State activeTab: TabId = 'tab-home';
292	  @State lastTabBeforePush: TabId = 'tab-home';
293	
294	  build() {
295	    Stack() {
296	      Stack({ alignContent: Alignment.Bottom }) {
297	        Column() {
298	          this.CurrentSurface()
299	        }
300	        .width('100%')
301	        .height('100%')
302	        .padding({
303	          bottom: this.isTabSurface(this.surface) ? Theme.bottomTabHeight + 8 : 0
304	        })
305	
306	        if (this.isTabSurface(this.surface)) {
307	          BottomTabBar({
308	            activeTab: this.activeTab,
309	            onTap: (tab: TabId): void => this.goToTab(tab),
310	          })
311	        }
312	      }
313	      .width('100%')
314	      .height('100%')
315	    }
316	    .width('100%')
317	    .height('100%')
318	    .backgroundColor(Theme.pageBg)
319	  }
320	
321	  @Builder
322	  CurrentSurface() {
323	    if (this.surface === 'home') {
324	      HomePage({
325	        goToTab: (tab: TabId): void => this.goToTab(tab),
326	        onCheckIn: (): void => this.openRecordsCheckIn(),
327	      })
328	    } else if (this.surface === 'wheel') {
329	      WheelPage({
330	        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
331	        onShareCard: (): void => this.pushSurface('share-card'),
332	        onAddCheckin: (dish: string): void => {
333	          // TODO: add check-in with dish
334	          this.goToTab('tab-records');
335	        },
336	      })
337	    } else if (this.surface === 'ingredients') {
338	      IngredientsPage({
339	        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
340	        onCook: (dish: string): void => {
341	          // TODO: mark as cooked
342	        },
343	      })
344	    } else if (this.surface === 'discover') {
345	      DiscoverPage({
346	        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
347	        onAddDish: (): void => {},
348	      })
349	    } else if (this.surface === 'records') {
350	      RecordsPage({
351	        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
352	        onShareCard: (): void => this.pushSurface('share-card'),
353	        onTodayCheckIn: (): void => {},
354	        onEdit: (id: string): void => {},
355	        onDelete: (id: string): void => this.deleteCheckIn(id),
356	      })
357	    } else if (this.surface === 'share-card') {
358	      ShareCardPage({
359	        onBack: (): void => this.returnToTab(this.lastTabBeforePush),
360	      })
361	    }
362	  }
363	
364	  private isTabSurface(s: AppSurface): boolean {
365	    return s === 'home' || s === 'wheel' || s === 'ingredients' || s === 'discover' || s === 'records';
366	  }
367	
368	  private goToTab(tab: TabId): void {
369	    this.activeTab = tab;
370	    if (tab === 'tab-home') {
371	      this.surface = 'home';
372	    } else if (tab === 'tab-wheel') {
373	      this.surface = 'wheel';
374	    } else if (tab === 'tab-ingredients') {
375	      this.surface = 'ingredients';
376	    } else if (tab === 'tab-discover') {
377	      this.surface = 'discover';
378	    } else if (tab === 'tab-records') {
379	      this.surface = 'records';
380	    }
381	  }
382	
383	  private returnToTab(tab: TabId): void {
384	    this.goToTab(tab);
385	  }
386	
387	  private pushSurface(surface: AppSurface): void {
388	    this.lastTabBeforePush = this.activeTab;
389	    this.surface = surface;
390	  }
391	
392	  private openRecordsCheckIn(): void {
393	    this.goToTab('tab-records');
394	  }
395	
